+fn validate_anthropic_base_url(base_url: &str) -> FcpResult<String> {
+    let parsed =
+        parse_anthropic_base_url(base_url).map_err(|message| FcpError::InvalidRequest {
+            code: 1003,
+            message,
+        })?;
